// 리스너
type Listener<T> = (value: T) => void;

// 내부 저장소 키
const VALUE = Symbol("ATOM_VALUE");
const LISTENERS = Symbol("ATOM_LISTENERS");

// 외부로 노출되는 타입 - 내부 심볼로 접근하여 직접 접근 불가능
export type Atom<T> = {
  readonly [VALUE]: T;
  readonly [LISTENERS]: Set<Listener<T>>;
};

export const createAtom = <T>(initialValue: T): Atom<T> => {
  return {
    [VALUE]: initialValue,
    [LISTENERS]: new Set(),
  };
};

export const get = <T>(atom: Atom<T>): T => {
  return atom[VALUE];
};

export const set = <T>(atom: Atom<T>, newValue: T) => {
  if (Object.is(atom[VALUE], newValue)) return;

  (atom as { [VALUE]: T })[VALUE] = newValue;
  atom[LISTENERS].forEach((listener) => listener(newValue));
};

export function subscribe<T>(atom: Atom<T>, callback: Listener<T>): () => void {
  const listeners = atom[LISTENERS];
  listeners.add(callback);
  callback(atom[VALUE]);

  return () => listeners.delete(callback);
}
